// // This module implements a 2-bit binary down/up counter with asynchronous reset and enable. It decrements when dir is high and increments when dir is low.
module up_down_counter (
    input clk,
    input reset,
    input enable,
    input dir,
    output reg [1:0] count
);always @(posedge clk) begin
        if (reset)
            count <= 2'b00;
        else if (enable)
            if (dir)
                count <= count + 1;
            else
                count <= count - 1;
    end

endmodule
